package com.example.democuoikybackend.adapter;

/**
 * Factory for creating DataConverter implementations based on ConverterType.
 */
public final class ConverterFactory {
    private ConverterFactory() {
    }

    public static DataConverter from(ConverterType type) {
        ConverterType t = (type == null) ? ConverterType.GSON : type;
        return switch (t) {
            case GSON -> new GSonAdapter();
            case JACKSON -> new JacksonAdapter();
            case JAXB -> new JaxAdapter();
        };
    }

    /** Backward compatible entry point (kept for current usages). */
    public static DataConverter fromName(String name) {
        return from(ConverterType.from(name));
    }
}

package com.example.democuoikybackend.adapter;

import java.util.Locale;

public enum ConverterType {
    GSON,
    JACKSON,
    JAXB;

    public static ConverterType from(String name) {
        String n = name == null ? "" : name.trim().toLowerCase(Locale.ROOT);
        return switch (n) {
            case "gson", "json-gson" -> GSON;
            case "jackson", "json-jackson", "json" -> JACKSON;
            case "jaxb", "xml", "jax" -> JAXB;
            default -> GSON;
        };
    }

    public boolean isXml() {
        return this == JAXB;
    }
}

package com.example.democuoikybackend.adapter;

/**
 * @deprecated Use {@link ConverterFactory} instead.
 */
@Deprecated
public final class DataConverterFactory {
    private DataConverterFactory() {
    }

    public static DataConverter from(ConverterType type) {
        return ConverterFactory.from(type);
    }

    public static DataConverter fromName(String name) {
        return ConverterFactory.fromName(name);
    }
}

package com.example.democuoikybackend.adapter;

import com.example.democuoikybackend.model.Laborer;
import jakarta.xml.bind.JAXBContext;
import jakarta.xml.bind.Marshaller;
import jakarta.xml.bind.Unmarshaller;
import java.io.StringReader;
import java.io.StringWriter;

public class JaxAdapter implements DataConverter {
    private Unmarshaller jaxbUnmarshaller;

    @Override
    public Laborer parse(String data) {
        return parse2(data);
    }

    @Override
    public String stringify(Object obj) {
        return stringify2(obj);
    }

    // Các hàm xử lý chi tiết JAXB
    public Laborer parse2(String data) {
        try {
            JAXBContext jaxbContext = JAXBContext.newInstance(Laborer.class);
            jaxbUnmarshaller = jaxbContext.createUnmarshaller();
            StringReader reader = new StringReader(data);
            return (Laborer) jaxbUnmarshaller.unmarshal(reader);
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

    public String stringify2(Object obj) {
        try {
            // Lấy class của object đang truyền vào (List hoặc Laborer)
            JAXBContext jaxbContext = JAXBContext.newInstance(obj.getClass());
            Marshaller jaxbMarshaller = jaxbContext.createMarshaller();
            StringWriter writer = new StringWriter();
            jaxbMarshaller.marshal(obj, writer);
            return writer.toString();
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }
}

package com.example.democuoikybackend.adapter;

import com.example.democuoikybackend.model.Laborer;
import jakarta.xml.bind.JAXBContext;
import jakarta.xml.bind.Marshaller;
import jakarta.xml.bind.Unmarshaller;

import java.io.StringReader;
import java.io.StringWriter;

public class JaxAdapter implements DataConverter {

    @Override
    public Laborer parse(String data) {
        try {
            JAXBContext jaxbContext = JAXBContext.newInstance(Laborer.class);
            Unmarshaller unmarshaller = jaxbContext.createUnmarshaller();
            return (Laborer) unmarshaller.unmarshal(new StringReader(data));
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

    @Override
    public String stringify(Object obj) {
        try {
            JAXBContext jaxbContext = JAXBContext.newInstance(obj.getClass());
            Marshaller marshaller = jaxbContext.createMarshaller();
            StringWriter writer = new StringWriter();
            marshaller.marshal(obj, writer);
            return writer.toString();
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }
}

package com.example.democuoikybackend.controller;

import com.example.democuoikybackend.adapter.DataConverter;
import com.example.democuoikybackend.adapter.GSonAdapter;
import com.example.democuoikybackend.command.*;
import com.example.democuoikybackend.model.Laborer;
import com.example.democuoikybackend.service.LaborerService;
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.*;
import java.io.IOException;
import java.util.stream.Collectors;

@WebServlet("/api/laborers/*")
public class LaborerController extends HttpServlet {
    private LaborerService laborerService;
    private DataConverter dataConverter;

    @Override
    public void init() {
        this.laborerService = new LaborerService();
    }

    // Lấy danh sách (GET)
    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse res) throws IOException {
        // 1. Tạo Command
        GetAllLaboreCommand getCmd = new GetAllLaboreCommand();

        // 2. Yêu cầu Service thực thi
        laborerService.executeCommand(getCmd);

        // 3. Lấy kết quả từ Command ra
        String responseData = dataConverter.stringify(getCmd.getResultList());

        res.setContentType("application/json; charset=UTF-8");
        res.getWriter().write(responseData);
    }

    // Thêm/Cập nhật (POST)
    @Override
    protected void doPost(HttpServletRequest req, HttpServletResponse res) throws IOException {
        String requestData = req.getReader().lines().collect(Collectors.joining());

        // Dùng Adapter để parse (chuyển JSON string -> Object)
        Laborer laborer = dataConverter.parse(requestData);

        Command addCmd = new AddLaborerCommand(laborer);
        laborerService.executeCommand(addCmd);

        res.setStatus(HttpServletResponse.SC_CREATED);
        res.getWriter().write("{\"message\": \"Lưu thành công!\"}");
    }

    // Xóa (DELETE) - /api/laborers?id=1
    @Override
    protected void doDelete(HttpServletRequest req, HttpServletResponse res) throws IOException {
        String idParam = req.getParameter("id");
        if (idParam != null) {
            // 1. Tạo Command xóa
            Command deleteCmd = new DeleteLaborerCommand(Integer.parseInt(idParam));

            // 2. Yêu cầu Service thực thi
            laborerService.executeCommand(deleteCmd);

            res.setStatus(HttpServletResponse.SC_OK);
            res.getWriter().write("{\"message\": \"Xóa thành công!\"}");
        }
    }
}

package com.example.democuoikybackend.controller;

import com.example.democuoikybackend.adapter.ConverterType;
import com.example.democuoikybackend.adapter.DataConverter;
import com.example.democuoikybackend.adapter.ConverterFactory;
import com.example.democuoikybackend.command.*;
import com.example.democuoikybackend.model.Laborer;
import com.example.democuoikybackend.service.LaborerService;
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.*;
import jakarta.servlet.ServletException;
import java.io.IOException;
import java.util.stream.Collectors;

@WebServlet("/api/laborers/*")
public class LaborerController extends HttpServlet {
    private LaborerService laborerService;

    @Override
    public void init() throws ServletException {
        super.init();
        this.laborerService = new LaborerService();
    }

    // Lấy danh sách (GET)
    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse res) throws IOException {
        DataConverter dataConverter = resolveConverter(req);

        GetAllLaboreCommand getCmd = new GetAllLaboreCommand();
        laborerService.executeCommand(getCmd);

        String responseData = dataConverter.stringify(getCmd.getResultList());
        res.setContentType(resolveContentType(req));
        res.getWriter().write(responseData);
    }

    // Thêm/Cập nhật (POST)
    @Override
    protected void doPost(HttpServletRequest req, HttpServletResponse res) throws IOException {
        DataConverter dataConverter = resolveConverter(req);

        String requestData = req.getReader().lines().collect(Collectors.joining());
        Laborer laborer = dataConverter.parse(requestData);

        Command addCmd = new AddLaborerCommand(laborer);
        laborerService.executeCommand(addCmd);

        res.setStatus(HttpServletResponse.SC_CREATED);
        res.setContentType(resolveContentType(req));
        res.getWriter().write("{\"message\": \"Lưu thành công!\"}");
    }

    // Xóa (DELETE) - /api/laborers?id=1
    @Override
    protected void doDelete(HttpServletRequest req, HttpServletResponse res) throws IOException {
        // DELETE doesn't need body parsing, but keep content-type consistent
        String idParam = req.getParameter("id");
        if (idParam != null) {
            Command deleteCmd = new DeleteLaborerCommand(Integer.parseInt(idParam));
            laborerService.executeCommand(deleteCmd);

            res.setStatus(HttpServletResponse.SC_OK);
            res.setContentType(resolveContentType(req));
            res.getWriter().write("{\"message\": \"Xóa thành công!\"}");
        }
    }

    private DataConverter resolveConverter(HttpServletRequest req) {
        // Priority:
        // 1) query param: ?converter=gson|jackson|xml
        // 2) request Content-Type header (xml vs json)
        // 3) default: gson
        String converter = req.getParameter("converter");
        if (converter == null || converter.isBlank()) {
            String ct = req.getContentType();
            if (ct != null) {
                String lct = ct.toLowerCase();
                if (lct.contains("xml")) converter = "xml";
                else if (lct.contains("json")) converter = "json";
            }
        }
        ConverterType type = ConverterType.from(converter);
        return ConverterFactory.from(type);
    }

    private String resolveContentType(HttpServletRequest req) {
        String override = req.getParameter("converter");
        ConverterType type = ConverterType.from(override);
        return type.isXml() ? "application/xml; charset=UTF-8" : "application/json; charset=UTF-8";
    }
}

package com.example.democuoikybackend.hibernate;

import com.example.democuoikybackend.model.Laborer;
import com.example.democuoikybackend.util.HibernateUtil;
import org.hibernate.Session;
import org.hibernate.Transaction;
import java.util.List;

public class LaborerHibernate {
    public void save(Laborer laborer) {
        Transaction transaction = null;
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            transaction = session.beginTransaction();
            session.merge(laborer); // Dùng merge để lo cả Thêm và Sửa
            transaction.commit();
        } catch (Exception e) {
            if (transaction != null) transaction.rollback();
        }
    }

    public void delete(Integer id) {
        Transaction transaction = null;
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            transaction = session.beginTransaction();
            Laborer laborer = session.get(Laborer.class, id);
            if (laborer != null) session.remove(laborer);
            transaction.commit();
        } catch (Exception e) {
            if (transaction != null) transaction.rollback();
        }
    }

    public List<Laborer> findAll() {
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            return session.createQuery("from Laborer", Laborer.class).list();
        }
    }


}

package com.example.democuoikybackend.hibernate;

import com.example.democuoikybackend.model.Laborer;
import com.example.democuoikybackend.util.HibernateUtil;
import org.hibernate.Session;
import org.hibernate.Transaction;
import java.util.List;

public class LaborerHibernate {
    public void save(Laborer laborer) {
        Transaction transaction = null;
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            transaction = session.beginTransaction();
            session.merge(laborer); // Dùng merge để lo cả Thêm và Sửa
            transaction.commit();
        } catch (Exception e) {
            if (transaction != null) transaction.rollback();
        }
    }

    public void delete(Integer id) {
        Transaction transaction = null;
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            transaction = session.beginTransaction();
            Laborer laborer = session.get(Laborer.class, id);
            if (laborer != null) session.remove(laborer);
            transaction.commit();
        } catch (Exception e) {
            if (transaction != null) transaction.rollback();
        }
    }

    public List<Laborer> findAll() {
        try (Session session = HibernateUtil.getSessionFactory().openSession()) {
            // Use the fully qualified class name to avoid IDE/compile resolution issues
            String hql = "from " + Laborer.class.getName();
            return session.createQuery(hql, Laborer.class).list();
        }
    }


}

